#include <iostream>
#include <string>
#include <string_view>

class Base
{
protected:
    std::string m_name{ "unnamed" };

public:
    Base()
    {
        std::cout << "Base(" << m_name << ") constructed\n";
    }

    ~Base()
    {
        std::cout << "Base(" << m_name << ") destroyed\n";
    }
};

class Derived : public Base
{
public:
    Derived(std::string_view name)
    {
        m_name = name;
        std::cout << "Derived(" << m_name << ") constructed\n";
    }

    ~Derived()
    {
        std::cout << "Derived(" << m_name << ") destroyed\n";
    }
};

int main()
{
    std::string name{};
    std::cin >> name;

    {
        Derived d{ name };
    }

    return 0;
}

