class Animal
{
public:
    Animal()
    {
        std::cout << "Animal constructed\n";
    }

    ~Animal()
    {
        std::cout << "Animal destroyed\n";
    }
};

class Pet : public Animal
{
protected:
    std::string m_name;

public:
    Pet(std::string_view name)
    {
        m_name = name;
        std::cout << "Pet(" << m_name << ") constructed\n";
    }

    ~Pet()
    {
        std::cout << "Pet(" << m_name << ") destroyed\n";
    }
};

class Dog : public Pet
{
    std::string m_breed;

public:
    Dog(std::string_view name, std::string_view breed)
        : Pet{ name }
    {
        m_breed = breed;
        std::cout << "Dog(" << m_name << ", " << m_breed << ") constructed\n";
    }

    ~Dog()
    {
        std::cout << "Dog(" << m_name << ", " << m_breed << ") destroyed\n";
    }
};

int main()
{
    std::string name{};
    std::cin >> name;

    std::string breed{};
    std::cin >> breed;

    {
        Dog d{ name, breed };
    }

    return 0;
}
